from tokenizer import tokenize


def evaluate(expr):
    tokens = tokenize(expr)
    result = int(tokens[0])
    i = 1
    while i < len(tokens):
        op = tokens[i]
        rhs = int(tokens[i + 1])
        if op == "+":
            result += rhs
        elif op == "-":
            result -= rhs
        elif op == "*":
            result *= rhs
        elif op == "/":
            result //= rhs
        i += 2
    return result
